def test_merge_asof_indicator_true():
    # Test that indicator=True adds a _merge column
    left = pd.DataFrame(
        {"time": [1, 5, 10], "left_val": ["a", "b", "c"]}, index=[0, 1, 2]
    )
    right = pd.DataFrame(
        {"time": [1, 2, 3, 6, 7], "right_val": [1, 2, 3, 6, 7]}, index=[0, 1, 2, 3, 4]
    )

    result = merge_asof(left, right, on="time", indicator=True)

    expected = pd.DataFrame(
        {
            "time": [1, 5, 10],
            "left_val": ["a", "b", "c"],
            "right_val": [1, 3, 7],
            "_merge": pd.Categorical(
                ["both", "both", "both"], categories=["left_only", "right_only", "both"]
            ),
        }
    )
    tm.assert_frame_equal(result, expected)


