def test_merge_asof_indicator_with_by():
    # Test indicator with by parameter
    left = pd.DataFrame(
        {
            "time": [1, 5, 10],
            "ticker": ["A", "A", "A"],
            "left_val": ["a", "b", "c"],
        }
    )
    right = pd.DataFrame(
        {
            "time": [1, 2, 3, 6, 7],
            "ticker": ["A", "A", "A", "A", "A"],
            "right_val": [1, 2, 3, 6, 7],
        }
    )

    result = merge_asof(
        left, right, on="time", by="ticker", indicator=True
    )

    expected = pd.DataFrame(
        {
            "time": [1, 5, 10],
            "ticker": ["A", "A", "A"],
            "left_val": ["a", "b", "c"],
            "right_val": [1, 3, 7],
            "_merge": pd.Categorical(
                ["both", "both", "both"], categories=["left_only", "right_only", "both"]
            ),
        }
    )
    tm.assert_frame_equal(result, expected)


def test_merge_asof_indicator_invalid_column_name():
    # Test that indicator raises when column already exists
    left = pd.DataFrame(
        {"time": [1, 5, 10], "left_val": ["a", "b", "c"], "_merge": [1, 1, 1]}
    )
    right = pd.DataFrame(
        {"time": [1, 2, 3, 6, 7], "right_val": [1, 2, 3, 6, 7]}
    )

    msg = "Cannot use name of an existing column for indicator column"
    with pytest.raises(ValueError, match=msg):
        merge_asof(left, right, on="time", indicator=True)


def test_merge_asof_indicator_invalid_argument():
    # Test that indicator raises for invalid argument type
    left = pd.DataFrame(
        {"time": [1, 5, 10], "left_val": ["a", "b", "c"]}
    )
    right = pd.DataFrame(
        {"time": [1, 2, 3, 6, 7], "right_val": [1, 2, 3, 6, 7]}
    )

